import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Maximum size for user input
        int maxLength = 10;

        // Truncate user input if it exceeds maxLength
        userInput = userInput.substring(0, Math.min(userInput.length(), maxLength));

        char[] buffer = new char[maxLength];

        // Copy the sanitized user input into the buffer
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Welcome, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
